#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define TABLE_SIZE 11

/* Node structure for linked list in separate chaining */
typedef struct Node {
 int key;
 int value;
 struct Node* next;
} Node;

/* Hash table structure */
typedef struct {
 Node* buckets[TABLE_SIZE]; /* Array of pointers to linked lists */
 int count; /* Number of elements in table */
} HashTable;

/* Initialize hash table */
void initTable(HashTable* ht) {
 int i;
 for (i = 0; i < TABLE_SIZE; i++) {
 ht->buckets[i] = NULL;
 }
 ht->count = 0;
}

/* Hash function using division method */
int hashFunction(int key) {
 return key % TABLE_SIZE;
}

/* Insert into hash table using separate chaining */
void insert(HashTable* ht, int key, int value) {
 int index = hashFunction(key);

 /* Check if key already exists, update if so */
 Node* current = ht->buckets[index];
 while (current != NULL) {
 if (current->key == key) {
 current->value = value;
 printf("Updated key %d at index %d\n", key, index);
 return;
 }
 current = current->next;
 }

 /* Create new node and insert at head */
 Node* newNode = (Node*)malloc(sizeof(Node));
 newNode->key = key;
 newNode->value = value;
 newNode->next = ht->buckets[index]; /* Insert at beginning */
 ht->buckets[index] = newNode;
 ht->count++;

 printf("Inserted key %d at index %d\n", key, index);
}

/* Search for key in hash table */
int search(HashTable* ht, int key) {
 int index = hashFunction(key);
 Node* current = ht->buckets[index];

 while (current != NULL) {
 if (current->key == key) {
 return current->value;
 }
 current = current->next;
 }

 return -1; /* Not found */
}

/* Delete key from hash table */
int delete(HashTable* ht, int key) {
 int index = hashFunction(key);
 Node* current = ht->buckets[index];
 Node* prev = NULL;

 while (current != NULL) {
 if (current->key == key) {
 if (prev == NULL) {
 /* Delete head node */
 ht->buckets[index] = current->next;
 } else {
 /* Delete middle or last node */
 prev->next = current->next;
 }
 free(current);
 ht->count--;
 return 1; /* Success */
 }
 prev = current;
 current = current->next;
 }

 return 0; /* Not found */
}

/* Display hash table */
void display(HashTable* ht) {
 int i;
 Node* current;

 printf("\n===== Hash Table Contents =====\n");
 for (i = 0; i < TABLE_SIZE; i++) {
 printf("Bucket %2d: ", i);
 current = ht->buckets[i];

 if (current == NULL) {
 printf("NULL");
 } else {
 while (current != NULL) {
 printf("[%d,%d] -> ", current->key, current->value);
 current = current->next;
 }
 printf("NULL");
 }
 printf("\n");
 }
 printf("-------------------------------\n");
 printf("Load Factor (alpha): %.2f\n", (float)ht->count / TABLE_SIZE);
}

/* Free all memory */
void freeTable(HashTable* ht) {
 int i;
 Node* current;
 Node* temp;

 for (i = 0; i < TABLE_SIZE; i++) {
 current = ht->buckets[i];
 while (current != NULL) {
 temp = current;
 current = current->next;
 free(temp);
 }
 }
}

/* Main function demonstrating the hash table */
int main() {
 HashTable ht;
 int keys[] = {20, 31, 42, 53, 64, 75, 86, 9, 15, 27};
 int n = sizeof(keys) / sizeof(keys[0]);
 int i;
 int result;

 initTable(&ht);

 printf("=== Inserting Keys into Hash Table ===\n");
 for (i = 0; i < n; i++) {
 printf("h(%d) = %d %% %d = %d\t", 
 keys[i], keys[i], TABLE_SIZE, keys[i] % TABLE_SIZE);
 insert(&ht, keys[i], keys[i] * 10);
 }

 display(&ht);

 /* Search operations */
 printf("\n=== Search Operations ===\n");
 result = search(&ht, 15);
 printf("Search(15): %s\n", result != -1 ? "Found" : "Not Found");

 result = search(&ht, 99);
 printf("Search(99): %s\n", result != -1 ? "Found" : "Not Found");

 /* Delete operation */
 printf("\n=== Delete Operations ===\n");
 printf("Delete(31): %s\n", delete(&ht, 31) ? "Deleted" : "Not Found");
 printf("Delete(99): %s\n", delete(&ht, 99) ? "Deleted" : "Not Found");

 display(&ht);

 /* Clean up */
 freeTable(&ht);

 return 0;
}

/**
 * Static Hash Table Implementation using Linear Probing (Open Addressing)
 * Hash Function: Division Method (key % tableSize)
 * Collision Resolution: Linear Probing (h(key, i) = (h(key) + i) % m)
 */
class LinearProbingHashTable {
 private static final int TABLE_SIZE = 11;
 private static final int EMPTY = -1;
 private static final int DELETED = -2;

 private int[] keys;
 private int[] values;
 private int[] status; // -1 = EMPTY, -2 = DELETED, >= 0 = OCCUPIED
 private int count;

 public LinearProbingHashTable() {
 keys = new int[TABLE_SIZE];
 values = new int[TABLE_SIZE];
 status = new int[TABLE_SIZE];
 count = 0;

 // Initialize all slots as empty
 for (int i = 0; i < TABLE_SIZE; i++) {
 status[i] = EMPTY;
 }
 }

 // Division method hash function
 private int hash(int key) {
 return key % TABLE_SIZE;
 }

 // Linear probing: probe sequence h(key), h(key)+1, h(key)+2, ...
 private int probe(int h0, int i) {
 return (h0 + i) % TABLE_SIZE;
 }

 /**
 * Insert key-value pair using linear probing
 * Uses lazy deletion marker for deleted slots
 */
 public String insert(int key, int value) {
 if (count >= TABLE_SIZE) {
 return "Table is full";
 }

 int h0 = hash(key);

 for (int i = 0; i < TABLE_SIZE; i++) {
 int index = probe(h0, i);

 // Found empty or deleted slot
 if (status[index] == EMPTY || status[index] == DELETED) {
 keys[index] = key;
 values[index] = value;
 status[index] = key; // Mark as occupied with key
 count++;
 return "Inserted key " + key + " at index " + index;
 }

 // Key already exists, update value
 if (status[index] == key) {
 values[index] = value;
 return "Updated key " + key + " at index " + index;
 }
 }

 return "Table is full";
 }

 /**
 * Search for key using linear probing
 * Stops at first EMPTY slot (key not found)
 * Continues past DELETED slots (lazy deletion)
 */
 public Integer search(int key) {
 int h0 = hash(key);

 for (int i = 0; i < TABLE_SIZE; i++) {
 int index = probe(h0, i);

 // Empty slot means key doesn't exist
 if (status[index] == EMPTY) {
 return null;
 }

 // Found the key
 if (status[index] == key) {
 return values[index];
 }
 // Continue searching past deleted slots
 }

 return null; // Not found
 }

 /**
 * Delete using lazy deletion
 * Mark slot as DELETED instead of EMPTY to preserve search paths
 */
 public boolean delete(int key) {
 int h0 = hash(key);

 for (int i = 0; i < TABLE_SIZE; i++) {
 int index = probe(h0, i);

 // Empty slot means key doesn't exist
 if (status[index] == EMPTY) {
 return false;
 }

 // Found the key to delete
 if (status[index] == key) {
 status[index] = DELETED; // Lazy deletion
 count--;
 return true;
 }
 }

 return false;
 }

 /**
 * Display the hash table contents
 */
 public void display() {
 System.out.println("\n=== Hash Table Contents (Linear Probing) ===");
 System.out.println("Index | Key | Value | Status");
 System.out.println("------|-----|-------|-------");

 for (int i = 0; i < TABLE_SIZE; i++) {
 String statusStr;
 if (status[i] == EMPTY) {
 statusStr = "EMPTY";
 } else if (status[i] == DELETED) {
 statusStr = "DELETED";
 } else {
 statusStr = "OCCUPIED";
 }

 String keyStr = (status[i] >= 0) ? String.valueOf(keys[i]) : "-";
 String valStr = (status[i] >= 0) ? String.valueOf(values[i]) : "-";

 System.out.printf("%5d | %3s | %5s | %s%n", i, keyStr, valStr, statusStr);
 }

 System.out.println("---------------------------------");
 System.out.printf("Load Factor (α): %.2f%n", (double) count / TABLE_SIZE);
 }

 public int getCount() {
 return count;
 }
}

/**
 * Main class to demonstrate Linear Probing Hash Table
 */
public class LinearProbingDemo {
 public static void main(String[] args) {
 LinearProbingHashTable ht = new LinearProbingHashTable();

 // Insert keys from worked example
 int[] keys = {20, 30, 2, 13, 25, 24, 10, 9};

 System.out.println("=== Inserting Keys (Linear Probing) ===");
 for (int key : keys) {
 String result = ht.insert(key, key * 100);
 int h0 = key % 11;
 System.out.println("h(" + key + ") = " + key + " % 11 = " + h0 + " → " + result);
 }

 ht.display();

 // Search operations
 System.out.println("\n=== Search Operations ===");
 Integer val = ht.search(13);
 System.out.println("Search(13): " + (val != null ? "Found: " + val : "Not Found"));

 val = ht.search(99);
 System.out.println("Search(99): " + (val != null ? "Found: " + val : "Not Found"));

 // Delete operation
 System.out.println("\n=== Delete Operations ===");
 System.out.println("Delete(30): " + (ht.delete(30) ? "Deleted" : "Not Found"));
 System.out.println("Delete(99): " + (ht.delete(99) ? "Deleted" : "Not Found"));

 ht.display();

 // Demonstrate clustering effect
 System.out.println("\n=== Demonstrating Primary Clustering ===");
 // Insert more keys to show clustering
 ht.insert(32, 3200);
 ht.insert(43, 4300);
 ht.display();
 }
}
